import "std/collections"
import "std/math"

func solve(points: Array<Array<Int64>>): Int64 {
    let MOD = 1000000007
    let n = points.length()
    if n < 4 {
        return 0
    }

    // Group points by y-coordinate
    let y_groups = collections.default_dict(Array<Array<Int64>>)
    for point in points {
        let x = point[0]
        let y = point[1]
        y_groups[y].push(point)
    }

    var count: Int64 = 0

    // Iterate over all pairs of y-coordinates (y1, y2)
    let ys = y_groups.keys()
    let m = ys.length()
    for i in 0..<m {
        for j in i+1..<m {
            let y1 = ys[i]
            let y2 = ys[j]
            let group1 = y_groups[y1]
            let group2 = y_groups[y2]
            let k1 = group1.length()
            let k2 = group2.length()
            if k1 >= 2 && k2 >= 2 {
                // Number of ways to choose 2 points from group1 and 2 from group2
                let c = math.comb(k1, 2) * math.comb(k2, 2)
                count = (count + c) % MOD
            }
        }
    }

    return count
}
